"use strict";(globalThis.webpackChunktanyaacjain_github_io=globalThis.webpackChunktanyaacjain_github_io||[]).push([[8629],{6957:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>d,contentTitle:()=>o,default:()=>h,frontMatter:()=>s,metadata:()=>r,toc:()=>c});var i=t(4848),a=t(8453);const s={title:"Reliably Generating AI Code",tags:["engineering-thesis"],authors:"tanya",date:new Date("2025-10-15T00:00:00.000Z")},o=void 0,r={permalink:"/writings/reliable-ai-coding",source:"@site/writings/reliable-ai-coding.md",title:"Reliably Generating AI Code",description:"In 2025, writing boilerplate is cheap. Any junior dev with an LLM can spin up a Lambda, wire up logging, and handle CORS in minutes.",date:"2025-10-15T00:00:00.000Z",tags:[{inline:!1,label:"Engineering Thesis",permalink:"/writings/tags/engineering-thesis",description:"Opinionated system design ideas, proven in practice."}],readingTime:3.925,hasTruncateMarker:!1,authors:[{name:"Tanya Jain",title:"Author",url:"https://github.com/tanyaacjain",socials:{x:"tanyaacjain",github:"tanyaacjain"},imageURL:"https://github.com/tanyaacjain.png",key:"tanya"}],frontMatter:{title:"Reliably Generating AI Code",tags:["engineering-thesis"],authors:"tanya",date:"2025-10-15T00:00:00.000Z"},unlisted:!1,prevItem:{title:"The Good Intention's Sinkhole",permalink:"/writings/the-good-intention-sinkhole"},nextItem:{title:"ALiAS - Building a Tech Community Rooted in Ownership",permalink:"/writings/alias"}},d={authorsImageUrls:[void 0]},c=[{value:"1. Contract &gt; One-shot Coding",id:"1-contract--one-shot-coding",level:2},{value:"2. Zero-Cognitive-Load Adoption",id:"2-zero-cognitive-load-adoption",level:2},{value:"3. Eradicating Bug Classes and Data Corruption",id:"3-eradicating-bug-classes-and-data-corruption",level:2},{value:"4. Design for the 3AM Page",id:"4-design-for-the-3am-page",level:2},{value:"5. Descoping is a Design Tool",id:"5-descoping-is-a-design-tool",level:2},{value:"Conclusion",id:"conclusion",level:2}];function l(e){const n={a:"a",blockquote:"blockquote",em:"em",h2:"h2",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.p,{children:"In 2025, writing boilerplate is cheap. Any junior dev with an LLM can spin up a Lambda, wire up logging, and handle CORS in minutes."}),"\n",(0,i.jsx)(n.p,{children:"However, AI doesn\u2019t understand organizational rules or know your team\u2019s error-handling conventions. It forgets your patterns unless you either repeat them, or cache them into context - consuming a ton of tokens regardless."}),"\n",(0,i.jsx)(n.p,{children:'Left unguided, AI-generated code creates entropy and scales poorly. A codebase where every function looks different, debugging requires archaeology, and "it works on my machine" becomes the standard. Hence, job descriptions have switched from finding engineers who just write code to ensuring code behaves as intended.'}),"\n",(0,i.jsx)(n.h2,{id:"1-contract--one-shot-coding",children:"1. Contract > One-shot Coding"}),"\n",(0,i.jsx)(n.p,{children:"We stopped asking devs to write Lambda handlers. Instead, I built a [framework] that helps the developer focus on writing the business logic, by handling the plumbing. The first deploy works every time. What used to take hours to weeks, now is done in a day on average."}),"\n",(0,i.jsx)(n.p,{children:"Now, when a developer (or their AI assistant) scaffolds a new service, they don\u2019t write plumbing. They implement a strict interface. The logging, retries, tracing, and error normalization are enforced by the framework, not by convention."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Why this matters in the AI era:"})}),"\n",(0,i.jsx)(n.p,{children:"AI is great at filling in blanks. It is terrible at maintaining architectural integrity across 50 microservices, if not given the proper infrastructure to work with. By hardening the [framework], I ensure that whether a human or an AI writes the business logic, the system behavior is identical."}),"\n",(0,i.jsx)(n.p,{children:"A new hire ships on day three because the system is designed to onboard them fast without needing to understand the full system yet."}),"\n",(0,i.jsx)(n.p,{children:"What would have just been a 4x multiplier, is also maintaining the system's integrity."}),"\n",(0,i.jsx)(n.h2,{id:"2-zero-cognitive-load-adoption",children:"2. Zero-Cognitive-Load Adoption"}),"\n",(0,i.jsxs)(n.p,{children:["We built an ",(0,i.jsx)(n.a,{href:"/tech/aaa/invisible-integration-architecture",children:"invisible architecture in a system"}),". Product teams across AAA adopted it without having to sell it to them, or asking anyone to attend integration workshops."]}),"\n",(0,i.jsx)(n.p,{children:"In a world where AI can generate infinite features, the bottleneck isn\u2019t creation, it\u2019s integration. When your internal tools require meetings, docs, or config files, it's natural to meet more resistance to adopt. This invisible architecture adopts itself because it offers immediate value with zero cognitive load."}),"\n",(0,i.jsx)(n.p,{children:"This idea holds value in different forms across unique systems."}),"\n",(0,i.jsx)(n.h2,{id:"3-eradicating-bug-classes-and-data-corruption",children:"3. Eradicating Bug Classes and Data Corruption"}),"\n",(0,i.jsx)(n.p,{children:"We had a silent data-loss bug in MongoDB. An AI might fix the specific instance. A senior dev might patch the service."}),"\n",(0,i.jsx)(n.p,{children:"I fixed the client."}),"\n",(0,i.jsx)(n.p,{children:"I wrote [21 LOC] and injected it into our shared database layer. Now, no one \u2014 human or AI \u2014 can write code that overwrites data. The entire class of this bug is extinct. This is the difference between coding and engineering. Engineering eliminates the category of error. Coding alone might just hide the symptom."}),"\n",(0,i.jsx)(n.h2,{id:"4-design-for-the-3am-page",children:"4. Design for the 3AM Page"}),"\n",(0,i.jsx)(n.p,{children:"Our sync jobs used to page us at 3 AM. We replaced them with self-healing state machines. They retry, back off, and recover automatically. Now, there's hardly a page in a year."}),"\n",(0,i.jsx)(n.p,{children:"AI can write a cron job. It cannot easily design a system that anticipates failure modes, handles race conditions, and recovers without human intervention as it requires deep system understanding. To even address the problem, it requires empathy for the person on call."}),"\n",(0,i.jsx)(n.h2,{id:"5-descoping-is-a-design-tool",children:"5. Descoping is a Design Tool"}),"\n",(0,i.jsx)(n.p,{children:"Every quarterly planning cycle starts with multiple feature requests for various epics. Since AI is endlessly generative, it will happily write all the code. It doesn't mean it should. With no concept of ROI, AI doesn't ask whether a feature deserves to exist."}),"\n",(0,i.jsx)(n.p,{children:"What you don't build matters as much as what you do. Every line of code can become a liability. It needs tests to write, a feature to maintain and if anything breaks, a bug to fix, and a potential page at 3 AM."}),"\n",(0,i.jsx)(n.p,{children:"Engineering judgment is the filter against that entropy."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"What can we remove? What can we simplify? What shouldn\u2019t exist at all?"})}),"\n",(0,i.jsx)(n.p,{children:"A descoping pass ensures product is built for its end-users, not for AI's generative capacity."}),"\n",(0,i.jsx)(n.h2,{id:"conclusion",children:"Conclusion"}),"\n",(0,i.jsxs)(n.blockquote,{children:["\n",(0,i.jsx)(n.p,{children:"In an AI-first world, velocity is becoming cheaper, and code is treated like a commodity. Integrity is what compounds here, especially when consistency is the spine."}),"\n"]}),"\n",(0,i.jsx)(n.p,{children:"Instead of being the hero who leaves vacation to fix breakage, I like architecting systems that can detect breakage and self-heal, so that they work even when no one is watching."}),"\n",(0,i.jsx)(n.p,{children:"P.S. Across the system\u2019s lifetime, during my role at AAA, this pattern has saved an estimated ~4,000 developer hours, and continues to compound by eliminating repeated fixes, debugging effort, and inconsistent behavior across services."})]})}function h(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},8453:(e,n,t)=>{t.d(n,{R:()=>o,x:()=>r});var i=t(6540);const a={},s=i.createContext(a);function o(e){const n=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),i.createElement(s.Provider,{value:n},e.children)}}}]);